import{_ as a,o as t,c as n,a0 as s}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"What the Tracker Does","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/what-is-the-tracker.md","filePath":"getting-started/what-is-the-tracker.md"}'),r={name:"getting-started/what-is-the-tracker.md"};function o(i,e,l,h,p,d){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="what-the-tracker-does" tabindex="-1">What the Tracker Does <a class="header-anchor" href="#what-the-tracker-does" aria-label="Permalink to &quot;What the Tracker Does&quot;">​</a></h1><p>The Kingshot Event Tracker is a scoreboard and record‑keeper for the game <em>Kingshot</em>. Instead of juggling screenshots and spreadsheets, your kingdom and alliances keep everything in one place: who your players are, how they did in each event, and who earned rewards.</p><p>This page explains the main ideas. Keep the <strong><a href="./glossary.html">Glossary</a></strong> handy — it defines every term used here.</p><h2 id="the-building-blocks" tabindex="-1">The building blocks <a class="header-anchor" href="#the-building-blocks" aria-label="Permalink to &quot;The building blocks&quot;">​</a></h2><p>The app is organized in layers, from the biggest group down to a single score. Each layer lives inside the one above it.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Kingdom</span></span>
<span class="line"><span>  └── Alliance</span></span>
<span class="line"><span>        └── Player</span></span>
<span class="line"><span>              └── Result  (one player&#39;s score in one event instance)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Event template  →  Event instance  →  Results</span></span></code></pre></div><ul><li><strong>Kingdom</strong> — the top level, matching an in‑game kingdom/server. A kingdom contains alliances.</li><li><strong>Alliance</strong> — a group of players inside a kingdom.</li><li><strong>Player</strong> — a single governor, belonging to an alliance. Players have things like power, alliance rank, and a nickname history.</li><li><strong>Event template</strong> — a <em>reusable definition</em> of an event, such as &quot;Bear Trap&quot; — its rules, how it&#39;s scored, and how many stages it has. Templates are the recipe, not a specific occurrence.</li><li><strong>Event instance</strong> — one <em>actual run</em> of an event on specific dates (for example, &quot;Bear Trap — March 3&quot;). This is where scores get recorded.</li><li><strong>Result</strong> — one player&#39;s score (or participation) in one event instance.</li></ul><p>The difference between a <strong>template</strong> and an <strong>instance</strong> matters a lot, so it has its own glossary entries: <a href="./glossary.html#event-template">template</a> and <a href="./glossary.html#event-instance">instance</a>.</p><h2 id="getting-scores-into-the-app" tabindex="-1">Getting scores into the app <a class="header-anchor" href="#getting-scores-into-the-app" aria-label="Permalink to &quot;Getting scores into the app&quot;">​</a></h2><p>There are two ways to record what happened in an event:</p><ol><li><strong>Screenshot imports.</strong> You upload screenshots from the game (a damage ranking, a points list, and so on). The app reads the names and numbers for you and shows them as a list of proposed rows for you to check. <strong>Nothing is saved to your players until you review and accept those rows</strong> — imports always start as a safe draft. See the <a href="./glossary.html#import">import</a> and <a href="./glossary.html#review-row">review row</a> glossary entries.</li><li><strong>Manual entry.</strong> You type the scores in yourself. This is handy for small events or fixing up an import.</li></ol><p>Both paths end the same way: reviewed numbers become <strong>results</strong> attached to an event instance.</p><h2 id="what-the-app-does-with-your-data" tabindex="-1">What the app does with your data <a class="header-anchor" href="#what-the-app-does-with-your-data" aria-label="Permalink to &quot;What the app does with your data&quot;">​</a></h2><p>Once results are in, the app turns them into useful views:</p><ul><li><strong>Dashboards and analytics</strong> — charts and summaries of how your kingdom, alliance, and players are doing.</li><li><strong>Reward eligibility</strong> — based on rules you set, the app flags which players earned rewards.</li><li><strong>History</strong> — nickname changes, past events, and an audit trail of who changed what.</li></ul><h2 id="who-runs-the-tracker" tabindex="-1">Who runs the tracker <a class="header-anchor" href="#who-runs-the-tracker" aria-label="Permalink to &quot;Who runs the tracker&quot;">​</a></h2><p>Different people have different <strong>roles</strong>, and each role can see and do different things:</p><ul><li><strong>Supreme Admin</strong> runs the whole platform.</li><li><strong>King</strong> (also called Kingdom Admin) runs one kingdom.</li><li><strong>Alliance Leader</strong> runs one alliance.</li><li><strong>Co‑Leader</strong> helps a leader with day‑to‑day tracking.</li><li><strong>Alliance Player</strong> is a view‑only member.</li></ul><p>For what each role can do, read <strong><a href="./../roles/overview.html">Roles Explained</a></strong>.</p><h2 id="what-s-paid-vs-free" tabindex="-1">What&#39;s paid vs. free <a class="header-anchor" href="#what-s-paid-vs-free" aria-label="Permalink to &quot;What&#39;s paid vs. free&quot;">​</a></h2><p>The platform can run on <strong>subscription plans</strong>. Every kingdom and alliance always has at least a free plan, and premium plans unlock extra features (deeper analytics, recommendations, larger limits). You don&#39;t need to understand the paid side to use the basics — it&#39;s covered in a later section. For now, the two terms worth knowing are <a href="./glossary.html#effective-plan">effective plan</a> and <a href="./glossary.html#grant">grant</a>.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="./glossary.html">Glossary</a> — learn the vocabulary.</li><li><a href="./logging-in.html">Log In &amp; Out</a> — get into the app.</li><li><a href="./navigating.html">Finding Your Way Around</a> — the layout.</li></ul>`,23)])])}const u=a(r,[["render",o]]);export{g as __pageData,u as default};
